// MARK: - 1. Data Models

struct Stock: Identifiable, Codable, Equatable {
    let id = UUID()
    let symbol: String
    let companyName: String
    var price: Double
    var change: Double
    var changePercent: Double

    static func mock(symbol: String) -> Stock {
        Stock(symbol: symbol, companyName: "\(symbol) Inc.", price: Double.random(in: 100...1000).rounded(to: 2),
              change: Double.random(in: -10...10).rounded(to: 2),
              changePercent: Double.random(in: -1...1).rounded(to: 2))
    }
}

enum TradeType: String, Codable {
    case buy = "Buy"
    case sell = "Sell"
}

enum TradeStatus: String, Codable {
    case pending = "Pending"
    case executed = "Executed"
    case failed = "Failed"
}

struct Trade: Identifiable, Codable {
    let id = UUID()
    let stockSymbol: String
    let type: TradeType
    let quantity: Int
    let price: Double // Price at the time of trade
    let timestamp: Date
    var status: TradeStatus

    static func mock(symbol: String, type: TradeType, quantity: Int, price: Double) -> Trade {
        Trade(stockSymbol: symbol, type: type, quantity: quantity, price: price, timestamp: Date(), status: .pending)
    }
}

struct PortfolioItem: Identifiable, Codable, Equatable {
    let id = UUID()
    let stockSymbol: String
    var quantity: Int
    var averageCost: Double // Average cost per share

    var currentValue: Double {
        // This would ideally use current market price, but for simplicity, we'll use averageCost
        // or assume a way to get current price
        quantity > 0 ? averageCost * Double(quantity) : 0.0
    }
}

