// MARK: - 3. Trading Manager (ViewModel)

class TradingManager: ObservableObject {
    @Published var stocks: [Stock] = []
    @Published var portfolio: [PortfolioItem] = []
    @Published var balance: Double = 100_000.00 // Starting balance
    @Published var tradeHistory: [Trade] = []
    @Published var isLoading: Bool = false
    @Published var errorMessage: String?

    private var apiService: APIServiceProtocol
    private var cancellables = Set<AnyCancellable>()
    private var marketDataTimer: AnyCancellable?

    init(apiService: APIServiceProtocol = MockAPIService()) {
        self.apiService = apiService
        setupMarketDataPolling()
    }

    func setupMarketDataPolling() {
        marketDataTimer?.cancel()
        marketDataTimer = Timer.publish(every: 5, on: .main, in: .common)
            .autoconnect()
            .sink { [weak self] _ in
                self?.fetchMarketData()
            }
        fetchMarketData() // Initial fetch
    }

    func fetchMarketData() {
        isLoading = true
        apiService.fetchMarketData()
            .receive(on: DispatchQueue.main)
            .sink { [weak self] completion in
                self?.isLoading = false
                switch completion {
                case .failure(let error):
                    self?.errorMessage = "Failed to fetch market data: \(error.localizedDescription)"
                    print("Error fetching market data: \(error)")
                case .finished:
                    break
                }
            } receiveValue: { [weak self] fetchedStocks in
                self?.stocks = fetchedStocks
                self?.errorMessage = nil
            }
            .store(in: &cancellables)
    }

    func executeTrade(type: TradeType, stock: Stock, quantity: Int) {
        guard quantity > 0 else {
            errorMessage = "Quantity must be greater than zero."
            return
        }

        let totalCost = stock.price * Double(quantity)

        if type == .buy {
            guard balance >= totalCost else {
                errorMessage = "Insufficient balance to buy \(quantity) shares of \(stock.symbol)."
                return
            }
        } else { // Sell
            guard let holding = portfolio.first(where: { $0.stockSymbol == stock.symbol }),
                  holding.quantity >= quantity else {
                errorMessage = "Not enough shares of \(stock.symbol) to sell."
                return
            }
        }

        let pendingTrade = Trade(stockSymbol: stock.symbol, type: type, quantity: quantity, price: stock.price, timestamp: Date(), status: .pending)
        tradeHistory.insert(pendingTrade, at: 0) // Add to history immediately

        isLoading = true
        apiService.executeTrade(trade: pendingTrade)
            .receive(on: DispatchQueue.main)
            .sink { [weak self] completion in
                self?.isLoading = false
                if case .failure(let error) = completion {
                    self?.errorMessage = "Trade execution failed: \(error.localizedDescription)"
                    self?.updateTradeStatus(tradeId: pendingTrade.id, newStatus: .failed)
                    print("Error executing trade: \(error)")
                }
            } receiveValue: { [weak self] executedTrade in
                self?.updateTradeStatus(tradeId: executedTrade.id, newStatus: executedTrade.status)
                if executedTrade.status == .executed {
                    self?.updatePortfolio(trade: executedTrade)
                    self?.errorMessage = nil
                } else if executedTrade.status == .failed {
                    self?.errorMessage = "Trade for \(executedTrade.stockSymbol) failed to execute."
                }
            }
            .store(in: &cancellables)
    }

    private func updateTradeStatus(tradeId: UUID, newStatus: TradeStatus) {
        if let index = tradeHistory.firstIndex(where: { $0.id == tradeId }) {
            tradeHistory[index].status = newStatus
        }
    }

    private func updatePortfolio(trade: Trade) {
        let totalTradeValue = trade.price * Double(trade.quantity)

        if trade.type == .buy {
            balance -= totalTradeValue
            if let index = portfolio.firstIndex(where: { $0.stockSymbol == trade.stockSymbol }) {
                let existingItem = portfolio[index]
                let newQuantity = existingItem.quantity + trade.quantity
                let newAverageCost = ((existingItem.averageCost * Double(existingItem.quantity)) + totalTradeValue) / Double(newQuantity)
                portfolio[index].quantity = newQuantity
                portfolio[index].averageCost = newAverageCost
            } else {
                portfolio.append(PortfolioItem(stockSymbol: trade.stockSymbol, quantity: trade.quantity, averageCost: trade.price))
            }
        } else { // Sell
            balance += totalTradeValue
            if let index = portfolio.firstIndex(where: { $0.stockSymbol == trade.stockSymbol }) {
                var existingItem = portfolio[index]
                existingItem.quantity -= trade.quantity
                if existingItem.quantity <= 0 {
                    portfolio.remove(at: index)
                } else {
                    portfolio[index] = existingItem // Update the remaining quantity
                }
            }
        }
        // Ensure balance doesn't go negative on buys (handled by guard), or portfolio items exist
        balance = balance.rounded(to: 2)
    }
}

