struct MarketView: View {
    @EnvironmentObject var tradingManager: TradingManager
    @State private var showingTradeSheet = false
    @State private var selectedStock: Stock?

    var body: some View {
        NavigationView {
            List {
                if tradingManager.isLoading && tradingManager.stocks.isEmpty {
                    ProgressView("Loading Market Data...")
                } else if let error = tradingManager.errorMessage {
                    Text(error)
                        .foregroundColor(.red)
                } else {
                    ForEach(tradingManager.stocks) { stock in
                        Button(action: {
                            selectedStock = stock
                            showingTradeSheet = true
                        }) {
                            StockRow(stock: stock)
                        }
                    }
                }
            }
            .navigationTitle("Market Watch")
            .sheet(isPresented: $showingTradeSheet) {
                if let stock = selectedStock {
                    TradeEntryView(stock: stock)
                        .environmentObject(tradingManager)
                }
            }
            .refreshable {
                tradingManager.fetchMarketData()
            }
        }
    }
}

