                Section("Stock Details") {
                    HStack {
                        Text("Symbol:")
                        Spacer()
                        Text(stock.symbol)
                    }
                    HStack {
                        Text("Company:")
                        Spacer()
                        Text(stock.companyName)
                    }
                    HStack {
                        Text("Current Price:")
