                        Text(stock.price, format: .currency(code: "USD"))
                    }
                }

                Section("Order Details") {
                    Picker("Type", selection: $tradeType) {
                        Text("Buy").tag(TradeType.buy)
                        Text("Sell").tag(TradeType.sell)
                    }
                    .pickerStyle(.segmented)

                    Stepper("Quantity: \(quantity)", value: $quantity, in: 1...1000)

                    HStack {
                        Text("Estimated Total:")
                        Spacer()
                        Text((stock.price * Double(quantity)), format: .currency(code: "USD"))
                    }
