struct PortfolioView: View {
    @EnvironmentObject var tradingManager: TradingManager

    var totalPortfolioValue: Double {
        tradingManager.portfolio.reduce(0) { sum, item in
            // For a real app, this would use the current market price of the stock
            // For this example, we'll use average cost or a simplified lookup
            if let currentStock = tradingManager.stocks.first(where: { $0.symbol == item.stockSymbol }) {
                return sum + (currentStock.price * Double(item.quantity))
            }
            return sum + item.currentValue // Fallback to average cost if market data not found
        }
    }

    var body: some View {
        NavigationView {
            List {
                Section("Account Summary") {
                    HStack {
                        Text("Cash Balance:")
                        Spacer()
                        Text(tradingManager.balance, format: .currency(code: "USD"))
                    }
                    HStack {
                        Text("Total Portfolio Value:")
                        Spacer()
                        Text(totalPortfolioValue, format: .currency(code: "USD"))
                    }
                    HStack {
                        Text("Net Worth:")
                        Spacer()
                        Text(tradingManager.balance + totalPortfolioValue, format: .currency(code: "USD"))
                    }
                }

                Section("Holdings") {
                    if tradingManager.portfolio.isEmpty {
                        Text("Your portfolio is empty.")
                            .foregroundColor(.gray)
                    } else {
                        ForEach(tradingManager.portfolio) { item in
                            PortfolioRow(item: item, currentPrice: tradingManager.stocks.first(where: { $0.symbol == item.stockSymbol })?.price)
                        }
                    }
                }
                
                Section("Trade History") {
                    if tradingManager.tradeHistory.isEmpty {
                        Text("No trades yet.")
                            .foregroundColor(.gray)
                    } else {
                        ForEach(tradingManager.tradeHistory) { trade in
                            TradeHistoryRow(trade: trade)
                        }
                    }
                }
            }
            .navigationTitle("Portfolio")
            .refreshable {
                tradingManager.fetchMarketData() // Refresh market data to update portfolio values
            }
        }
    }
}

struct PortfolioRow: View {
    let item: PortfolioItem
    let currentPrice: Double?

    var unrealizedGainLoss: Double {
        guard let price = currentPrice else { return 0 }
        return (price - item.averageCost) * Double(item.quantity)
    }

    var body: some View {
        HStack {
            VStack(alignment: .leading) {
                Text(item.stockSymbol)
                    .font(.headline)
                Text("Qty: \(item.quantity)")
                    .font(.subheadline)
                    .foregroundColor(.gray)
            }
            Spacer()
            VStack(alignment: .trailing) {
                if let price = currentPrice {
                    Text(price * Double(item.quantity), format: .currency(code: "USD"))
                        .font(.headline)
                    HStack {
                        Text("Avg Cost: \(item.averageCost, format: .currency(code: "USD"))")
                            .font(.caption)
                        if unrealizedGainLoss != 0 {
                            Text(unrealizedGainLoss, format: .currency(code: "USD"))
                                .font(.caption)
                                .foregroundColor(unrealizedGainLoss >= 0 ? .green : .red)
                        }
                    }
                } else {
                    Text("N/A")
                        .foregroundColor(.gray)
                }
            }
        }
    }
}

struct TradeHistoryRow: View {
    let trade: Trade

    var body: some View {
        HStack {
            VStack(alignment: .leading) {
                Text("\(trade.type.rawValue) \(trade.stockSymbol)")
                    .font(.headline)
                    .foregroundColor(trade.type == .buy ? .green : .red)
                Text("Qty: \(trade.quantity) @ \(trade.price, format: .currency(code: "USD"))")
                    .font(.subheadline)
                    .foregroundColor(.gray)
            }
            Spacer()
            VStack(alignment: .trailing) {
                Text(trade.timestamp, style: .time)
                    .font(.caption)
                Text(trade.status.rawValue)
                    .font(.subheadline)
                    .foregroundColor(trade.status == .executed ? .green : (trade.status == .failed ? .red : .orange))
            }
        }
    }
}

